<#
.SYNOPSIS
    gdotnet
#>
Write-Host "Searching for all .NET packages..." -ForegroundColor Cyan; $allPackages = @(); $searches = @("Microsoft.DotNet.SDK", "Microsoft.DotNet.Runtime", "Microsoft.DotNet.DesktopRuntime", "Microsoft.DotNet.AspNetCore", "Microsoft.DotNet.WindowsHosting"); foreach($search in $searches) { $rawOutput = winget search $search --accept-source-agreements 2>$null | Out-String; $lines = $rawOutput -split "`n" | Where-Object { $_ -match "Microsoft\.DotNet\." -and $_ -notmatch "^-+$" -and $_ -notmatch "^Name" }; foreach($line in $lines) { if($line -match "(Microsoft\.DotNet\.\S+)") { $allPackages += $matches[1] } } }; $knownPackages = @("Microsoft.DotNet.SDK.Preview", "Microsoft.DotNet.SDK.9", "Microsoft.DotNet.SDK.8", "Microsoft.DotNet.SDK.7", "Microsoft.DotNet.SDK.6", "Microsoft.DotNet.SDK.5", "Microsoft.DotNet.SDK.3_1", "Microsoft.DotNet.Runtime.Preview", "Microsoft.DotNet.Runtime.9", "Microsoft.DotNet.Runtime.8", "Microsoft.DotNet.Runtime.7", "Microsoft.DotNet.Runtime.6", "Microsoft.DotNet.Runtime.5", "Microsoft.DotNet.Runtime.3_1", "Microsoft.DotNet.DesktopRuntime.Preview", "Microsoft.DotNet.DesktopRuntime.9", "Microsoft.DotNet.DesktopRuntime.8", "Microsoft.DotNet.DesktopRuntime.7", "Microsoft.DotNet.DesktopRuntime.6", "Microsoft.DotNet.DesktopRuntime.5", "Microsoft.DotNet.DesktopRuntime.3_1", "Microsoft.DotNet.AspNetCore.Preview", "Microsoft.DotNet.AspNetCore.9", "Microsoft.DotNet.AspNetCore.8", "Microsoft.DotNet.AspNetCore.7", "Microsoft.DotNet.AspNetCore.6", "Microsoft.DotNet.AspNetCore.5", "Microsoft.DotNet.AspNetCore.3_1", "Microsoft.DotNet.WindowsHosting.Preview", "Microsoft.DotNet.WindowsHosting.9", "Microsoft.DotNet.WindowsHosting.8", "Microsoft.DotNet.WindowsHosting.7", "Microsoft.DotNet.WindowsHosting.6", "Microsoft.DotNet.WindowsHosting.5", "Microsoft.DotNet.WindowsHosting.3_1"); $allPackages += $knownPackages; $allPackages = $allPackages | Sort-Object -Unique; Write-Host "Found $($allPackages.Count) .NET packages to install" -ForegroundColor Yellow; foreach($pkg in $allPackages) { Write-Host "Installing: $pkg" -ForegroundColor Green; winget install --id $pkg --accept-package-agreements --silent --force 2>$null }; Write-Host "Refreshing PATH..." -ForegroundColor Cyan; $env:PATH = [System.Environment]::GetEnvironmentVariable("PATH", "Machine") + ";" + [System.Environment]::GetEnvironmentVariable("PATH", "User"); Write-Host "`n=== COMPREHENSIVE .NET INFO ===" -ForegroundColor Cyan; if(Get-Command dotnet -ErrorAction SilentlyContinue) { dotnet --info } else { Write-Host "dotnet command not found - checking installations..." -ForegroundColor Red; if(Test-Path "$env:ProgramFiles\dotnet\dotnet.exe") { & "$env:ProgramFiles\dotnet\dotnet.exe" --info } else { Write-Host "No .NET installation found" -ForegroundColor Red } }; Write-Host "`n=== ALL INSTALLED .NET SDKs ===" -ForegroundColor Yellow; if(Get-Command dotnet -ErrorAction SilentlyContinue) { dotnet --list-sdks } else { if(Test-Path "$env:ProgramFiles\dotnet\dotnet.exe") { & "$env:ProgramFiles\dotnet\dotnet.exe" --list-sdks } }; Write-Host "`n=== ALL INSTALLED .NET RUNTIMES ===" -ForegroundColor Magenta; if(Get-Command dotnet -ErrorAction SilentlyContinue) { dotnet --list-runtimes } else { if(Test-Path "$env:ProgramFiles\dotnet\dotnet.exe") { & "$env:ProgramFiles\dotnet\dotnet.exe" --list-runtimes } }; Write-Host "`n=== WINGET INSTALLED .NET PACKAGES ===" -ForegroundColor Blue; winget list | Where-Object { $_ -match "Microsoft\.DotNet\." }
